#include <bits/stdc++.h>
using namespace std;
int main(){
	int n,c,a[200005];
	long long ans=0;
	cin>>n>>c;
	for(int i=1;i<=n;i++)cin>>a[i];
	sort(a+1,a+n+1);
	for(int i=1,l=1,r=1;i<=n;i++){
	    while(r<n && a[r+1]-a[i]<=c)r++;
		while(l<=n && a[l]-a[i]<c)l++;
	    while(a[r+1]==a[l] && r<=n)r++;
	    if(a[l]-a[i]==c && a[r]-a[i]==c && r>=1)ans+=r-l+1;
	}
	cout<<ans;
	return 0;
}
